import { Router } from "express";
import { bookingController } from "./booking.controller.js";
import { cheakAuth } from "../../midddlware/cheakAuth.js";
import { Role } from "../../../generated/prisma/enums.js";
import { rateLimitMiddleware } from "../../midddlware/rateLimiter.js";
const router = Router();
router.post("/", rateLimitMiddleware, cheakAuth(Role.USER), bookingController.createBooking);
router.patch("/status", rateLimitMiddleware, cheakAuth(Role.ADMIN), bookingController.updateBookingStatus);
router.get("/my-bookings", rateLimitMiddleware, cheakAuth(Role.USER), bookingController.getMyBooking);
router.get("/:ideaId", rateLimitMiddleware, cheakAuth(Role.ADMIN), bookingController.getBookingsByIdea);
export const bookingRouter = router;
